{
  "name": "navivox-app",
  "version": "1.0.0",
  "description": "**Private voice/chat for your own Gormes agents.**",
  "main": "index.js",
  "directories": {
    "doc": "docs",
    "lib": "lib",
    "test": "test"
  },
  "scripts": {
    "test": "flutter test --concurrency=1",
    "web:e2e": "playwright test --config=playwright.config.mjs"
  },
  "repository": {
    "type": "git",
    "url": "git+https://github.com/TrebuchetDynamics/navivox-app.git"
  },
  "keywords": [],
  "author": "",
  "license": "ISC",
  "bugs": {
    "url": "https://github.com/TrebuchetDynamics/navivox-app/issues"
  },
  "homepage": "https://github.com/TrebuchetDynamics/navivox-app#readme",
  "dependencies": {
    "@playwright/test": "^1.60.0",
    "playwright": "^1.60.0"
  }
}

import { defineConfig } from '@playwright/test';

export default defineConfig({
  testDir: './playwright/tests',
  timeout: 60000,
  expect: { timeout: 10000 },
  retries: 1,
  workers: 2,
  use: {
    headless: true,
    viewport: { width: 1280, height: 900 },
    actionTimeout: 8000,
    launchOptions: {
      args: [
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--ignore-gpu-blocklist',
      ],
    },
  },
  projects: [
    {
      name: 'chromium',
      use: { browserName: 'chromium' },
    },
  ],
  reporter: [['list'], ['json', { outputFile: 'playwright/results.json' }]],
});
